  const { isOpen, toggle, openChat } = useHelpPanel();

  return (
    <div>
      <button onClick={toggle}>
        {isOpen ? 'Close' : 'Help'}
      </button>
      <button onClick={openChat}>
        Ask AI
      </button>
    </div>
  );
